#include <stdio.h>
#include <string.h>
#include <stdbool.h>

int countWords(char *str) {
    int count = 0;
    bool inWord = false;
    for (int i = 0; str[i] != '\0'; i++) {
        if (str[i] == ' ' || str[i] == '\n' || str[i] == '\t') {
            inWord = false;
        } else if (!inWord) {
            inWord = true;
            count++;
        }
    }
    return count;
}

int main() {
    char s[] = "One Two Three";
    printf("%d\n", countWords(s));
    return 0;
}
